<template>
	<div class="w">
        <div class="v">
            <div class="chat" v-if="isChatShow">
                <p>{{ chatText }}<i v-if="isChatGenerating" class="blink">_</i></p>
            </div>
            <div class="icon" :style="'background-image: url('+ loadImage +');'">
                <div><i :class="isChatPause ? 'flip' : ''"></i></div>
            </div>
        </div>
	</div>
</template>

<script>
import UILoader from '@/components/UILoader.vue';

import 'vue-awesome/icons/mobile';
import 'vue-awesome/icons/columns';
import 'vue-awesome/icons/square';


export default {
    components: { 
        UiLoader: UILoader
    },
    data() {
        return {
            isChatShow: false,
            isChatGenerating: false,
            isChatPause: false,
            charIndex: 0,
            chatConvo: '',
            chatGenerated: '...',
            chatPause: ['!', '.', ','],
        }
    },
    computed: {
        chatText() {
            return this.chatGenerated;
        },
        loadImage() {
            return require('@/assets/img/me.png');
        }
    },
    methods: {
        generateConvo() {
            if (this.charIndex < this.chatConvo.length) {
                let c = this.chatConvo.charAt(this.charIndex), speed = 50;
                this.isChatPause = false;
                if (this.chatPause.includes(c)) {
                    this.isChatPause = true;
                    speed = 500;
                }
                this.chatGenerated += c;
                this.charIndex++;
                setTimeout(this.generateConvo, speed);
            }  
        }
    },
    mounted() {
        this.chatConvo = this.$store.state.homeIntro;
        setTimeout(() => {
            this.isChatShow = true;
        },  2000);
        setTimeout(() => {
            this.isChatGenerating = true;
            this.chatGenerated = '';
            this.generateConvo();
        },  3000);
	}
}
</script>


