<template>
	<div class="__c_nb">
        <div class="__w">
            <div :class="['__p', isShowMenu ? 'toggled' : '']">
                <ul v-if="isMobileDevice">
                    <li v-for="(n,i) in navis" :key="n.link" @click="goLink(n.link)" :style="i == 3 ? 'padding-right: 0' : ''">{{ n.name }}</li>
                </ul>
                <b @click="goLink('home-index')">PAULCARAS</b>
            </div>
            <div class="__r" v-if="!isMobileDevice"></div>
            <div class="__q" v-if="!isMobileDevice">
                <ul>
                    <li v-for="(n,i) in navis" :key="n.link" @click="goLink(n.link)" :style="i == 3 ? 'padding-right: 0' : ''">{{ n.name }}</li>
                </ul>
            </div>
            <div class="__q" v-else>
                <ul>
                    <li @click="toggleMenu()"><v-icon :name="isShowMenu ? 'times' : 'bars'"></v-icon></li>
                </ul>
            </div>
        </div>
	</div>
</template>

<script>
import 'vue-awesome/icons/square';
import 'vue-awesome/icons/bars';
import 'vue-awesome/icons/times';
import 'vue-awesome/icons/th-large';

export default {
    data() {
        return {
            isShowMenu: false,
            routeName: 'home-index',
            navis: [
                { name: 'About', link: 'about-index', icon: 'square' },
                { name: 'Works', link: 'works-index', icon: 'square' },
                { name: 'Skills', link: 'skills-index', icon: 'square' },
                { name: 'Contact', link: 'contact-index', icon: 'square' }
            ]
        }
    },
    methods: {
        goLink(a) {
            this.routeName = a;
            this.$router.push({ name: a });
        },
        toggleMenu() {
            this.isShowMenu = !this.isShowMenu;
            if (!this.isShowMenu)
                this.$router.push({ name: 'home-index' });
        }
    },
    mounted() {
        this.routeName = this.$route.name;
    }
}
</script>


<style scoped>
.__c_nb { height: 52px; border-bottom: 1px solid #e0e0e0; background: linear-gradient(to right, #f8f8f8, #fff);  z-index: 9999; overflow-y: hidden;  }

.__w { display: grid; grid-template-columns: max-content auto max-content; max-width: var(--max-width); margin: 0 auto; }
.__c_nb .__w .__p { padding: 12px 0; position: relative; }
.__c_nb .__w .__p b, .__c_nb .__q ul li { font-size: 28px; font-family: "Teko"; text-transform: uppercase; }
.__c_nb .__w .__p b { font-weight: 500; display: block; position: absolute; top: 12px; transition: top 200ms ease-in-out; }
.__c_nb .__w .__q ul { list-style: none; display: block; }
.__c_nb .__w .__q ul li { display: inline-block; padding: 12px 10px; font-weight: 300; }
.__c_nb .__w .__q ul li svg { width: 28px; height: 28px; color: #222 }


@media only screen and (max-width: 1000px) {
    .__w { display: grid; grid-template-columns: auto 68px; }
    .__c_nb .__w .__p { padding: 12px 20px; }
    .__c_nb .__w .__p b { top: 12px; }
    .__c_nb .__w .__p.toggled b { top: 100% }
    .__c_nb .__w .__p ul { list-style: none; display: block; position: absolute; bottom: 100%; transition: bottom 200ms ease-in-out; }
    .__c_nb .__w .__p.toggled ul { bottom: 12px; }
    .__c_nb .__w .__p ul li { display: inline-block; padding-right: 12px; font-weight: 300; font-size: 28px; font-family: "Teko"; text-transform: uppercase;  }

    .__c_nb .__w .__q ul li { padding: 12px 20px;  }
    .__c_nb .__w .__q ul li svg { transition: all 500ms ease-in-out; }
}
